package user

import (
	"context"
	"fmt"
	"log"
	"net"

	pb "github.com/example/proto/userpb"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/status"
)

type UserServiceServer struct {
	pb.UnimplementedUserServiceServer
	db *Database
}

func NewUserServiceServer(db *Database) *UserServiceServer {
	return &UserServiceServer{db: db}
}

func (s *UserServiceServer) GetUser(ctx context.Context, req *pb.GetUserRequest) (*pb.User, error) {
	user, err := s.db.FindByID(ctx, req.GetId())
	if err != nil {
		if errors.Is(err, ErrNotFound) {
			return nil, status.Errorf(codes.NotFound, "user not found: %s", req.GetId())
		}
		return nil, status.Errorf(codes.Internal, "database error: %v", err)
	}

	return &pb.User{
		Id:        user.ID,
		Email:     user.Email,
		Name:      user.Name,
		CreatedAt: user.CreatedAt.Format(time.RFC3339),
	}, nil
}

func (s *UserServiceServer) CreateUser(ctx context.Context, req *pb.CreateUserRequest) (*pb.User, error) {
	user := &models.User{
		ID:       uuid.New().String(),
		Email:    req.GetUser().GetEmail(),
		Name:     req.GetUser().GetName(),
		Password: req.GetUser().GetPassword(),
	}

	if err := user.Validate(); err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "validation failed: %v", err)
	}

	hashedPassword, err := bcrypt.hashPassword(user.Password)
	if err != nil {
		return nil, status.Errorf(codes.Internal, "failed to hash password")
	}
	user.Password = hashedPassword

	created, err := s.db.Create(ctx, user)
	if err != nil {
		return nil, status.Errorf(codes.Internal, "failed to create user: %v", err)
	}

	return &pb.User{
		Id:        created.ID,
		Email:     created.Email,
		Name:      created.Name,
		CreatedAt: created.CreatedAt.Format(time.RFC3339),
	}, nil
}

func main() {
	lis, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatalf("failed to listen: %v", err)
	}

	db := NewDatabase()
	server := grpc.NewServer()
	pb.RegisterUserServiceServer(server, NewUserServiceServer(db))

	log.Println("gRPC server running on :50051")
	if err := server.Serve(lis); err != nil {
		log.Fatalf("failed to serve: %v", err)
	}
}

package domain

import (
	"errors"
	"time"
)

var (
	ErrOrderEmpty      = errors.New("order must have at least one item")
	ErrOrderCancelled  = errors.New("cannot modify cancelled order")
	ErrOrderPaid       = errors.New("order is already paid")
)

type OrderStatus string

const (
	StatusDraft   OrderStatus = "draft"
	StatusPaid    OrderStatus = "paid"
	StatusShipped OrderStatus = "shipped"
	StatusDone    OrderStatus = "done"
)

type Order struct {
	id        string
	items     []OrderItem
	status    OrderStatus
	createdAt time.Time
	updatedAt time.Time
}

type OrderItem struct {
	ProductID   string
	ProductName string
	Quantity    int
	Price       float64
}

func NewOrder(id string, items []OrderItem) (*Order, error) {
	if len(items) == 0 {
		return nil, ErrOrderEmpty
	}

	now := time.Now()
	return &Order{
		id:        id,
		items:     items,
		status:    StatusDraft,
		createdAt: now,
		updatedAt: now,
	}, nil
}

func (o *Order) AddItem(item OrderItem) error {
	if o.status != StatusDraft {
		return ErrOrderCancelled
	}
	o.items = append(o.items, item)
	o.updatedAt = time.Now()
	return nil
}

func (o *Order) Submit() error {
	if o.status != StatusDraft {
		return ErrOrderCancelled
	}
	if len(o.items) == 0 {
		return ErrOrderEmpty
	}
	o.status = StatusPaid
	o.updatedAt = time.Now()
	return nil
}

func (o *Order) Ship() error {
	if o.status != StatusPaid {
		return ErrOrderPaid
	}
	o.status = StatusShipped
	o.updatedAt = time.Now()
	return nil
}

func (o *Order) Total() float64 {
	total := 0.0
	for _, item := range o.items {
		total += item.Price * float64(item.Quantity)
	}
	return total
}

// Repository interface (ports)
type OrderRepository interface {
	Save(order *Order) error
	FindByID(id string) (*Order, error)
	FindAll() ([]*Order, error)
}

// Use case
type CreateOrderUseCase struct {
	repo OrderRepository
}

func NewCreateOrderUseCase(repo OrderRepository) *CreateOrderUseCase {
	return &CreateOrderUseCase{repo: repo}
}

func (uc *CreateOrderUseCase) Execute(items []OrderItem) (*Order, error) {
	order, err := NewOrder(uuid.New().String(), items)
	if err != nil {
		return nil, err
	}

	if err := uc.repo.Save(order); err != nil {
		return nil, err
	}

	return order, nil
}

package eventstore

import (
	"context"
	"encoding/json"
	"sync"
	"time"
)

type DomainEvent struct {
	ID          string    `json:"id"`
	AggregateID string    `json:"aggregate_id"`
	EventType   string    `json:"event_type"`
	Payload     []byte    `json:"payload"`
	Version     int       `json:"version"`
	Timestamp   time.Time `json:"timestamp"`
}

type EventStore struct {
	mu      sync.RWMutex
	events  map[string][]DomainEvent
	subs    map[string][]func(DomainEvent)
}

func NewEventStore() *EventStore {
	return &EventStore{
		events: make(map[string][]DomainEvent),
		subs:   make(map[string][]func(DomainEvent)),
	}
}

func (es *EventStore) Append(ctx context.Context, aggregateID string, event DomainEvent) error {
	es.mu.Lock()
	defer es.mu.Unlock()

	history := es.events[aggregateID]
	event.Version = len(history) + 1
	event.Timestamp = time.Now()

	es.events[aggregateID] = append(history, event)

	// Notify subscribers
	for _, handler := range es.subs[event.EventType] {
		go handler(event)
	}

	return nil
}

func (es *EventStore) GetEvents(ctx context.Context, aggregateID string) ([]DomainEvent, error) {
	es.mu.RLock()
	defer es.mu.RUnlock()

	return es.events[aggregateID], nil
}

func (es *EventStore) Subscribe(eventType string, handler func(DomainEvent)) {
	es.mu.Lock()
	defer es.mu.Unlock()

	es.subs[eventType] = append(es.subs[eventType], handler)
}

func (es *EventStore) RebuildState(aggregateID string, applyFn func([]byte, []byte) ([]byte, error)) ([]byte, error) {
	es.mu.RLock()
	defer es.mu.RUnlock()

	events := es.events[aggregateID]
	state := []byte(`{}`)

	for _, event := range events {
		var err error
		state, err = applyFn(state, event.Payload)
		if err != nil {
			return nil, err
		}
	}

	return state, nil
}

package workers

import (
	"context"
	"fmt"
	"sync"
	"time"
)

type Job struct {
	ID      int
	Payload string
}

type Result struct {
	JobID  int
	Output string
	Err    error
}

type WorkerPool struct {
	jobs     chan Job
	results  chan Result
	workers  int
	wg       sync.WaitGroup
}

func NewWorkerPool(workers int, queueSize int) *WorkerPool {
	return &WorkerPool{
		jobs:    make(chan Job, queueSize),
		results: make(chan Result, queueSize),
		workers: workers,
	}
}

func (wp *WorkerPool) Start(ctx context.Context) {
	for i := 0; i < wp.workers; i++ {
		wp.wg.Add(1)
		go wp.worker(ctx, i)
	}
}

func (wp *WorkerPool) worker(ctx context.Context, id int) {
	defer wp.wg.Done()

	for {
		select {
		case <-ctx.Done():
			fmt.Printf("Worker %d stopping\n", id)
			return
		case job, ok := <-wp.jobs:
			if !ok {
				return
			}
			result := wp.process(job)
			select {
			case wp.results <- result:
			case <-ctx.Done():
				return
			}
		}
	}
}

func (wp *WorkerPool) process(job Job) Result {
	time.Sleep(100 * time.Millisecond)
	return Result{
		JobID:  job.ID,
		Output: fmt.Sprintf("processed: %s", job.Payload),
	}
}

func (wp *WorkerPool) Submit(job Job) {
	wp.jobs <- job
}

func (wp *WorkerPool) Results() <-chan Result {
	return wp.results
}

func (wp *WorkerPool) Stop() {
	close(wp.jobs)
	wp.wg.Wait()
	close(wp.results)
}

func main() {
	pool := NewWorkerPool(4, 100)
	pool.Start(context.Background())

	for i := 0; i < 10; i++ {
		pool.Submit(Job{ID: i, Payload: fmt.Sprintf("task-%d", i)})
	}

	go pool.Stop()

	for result := range pool.Results() {
		fmt.Printf("Result: %s\n", result.Output)
	}
}

package sidecar

import (
	"context"
	"io"
	"log"
	"net/http"
	"time"
)

type SidecarConfig struct {
	ProxyPort     int
	BackendURL    string
	LogLevel      string
	MetricsPort   int
}

type Sidecar struct {
	config     SidecarConfig
	proxy      *http.Server
	metrics    *MetricsCollector
	logger     *log.Logger
}

func NewSidecar(cfg SidecarConfig) *Sidecar {
	return &Sidecar{
		config: cfg,
		metrics: NewMetricsCollector(),
		logger: log.New(os.Stdout, "[sidecar] ", log.LstdFlags),
	}
}

func (sc *Sidecar) Start() error {
	mux := http.NewServeMux()
	mux.HandleFunc("/", sc.proxyHandler)
	mux.HandleFunc("/health", sc.healthHandler)
	mux.HandleFunc("/metrics", sc.metricsHandler)

	sc.proxy = &http.Server{
		Addr:         fmt.Sprintf(":%d", sc.config.ProxyPort),
		Handler:      mux,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
	}

	sc.logger.Printf("Starting sidecar proxy on port %d", sc.config.ProxyPort)
	return sc.proxy.ListenAndServe()
}

func (sc *Sidecar) proxyHandler(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	proxyReq, err := http.NewRequestWithContext(r.Context(), r.Method, sc.config.BackendURL+r.URL.Path, r.Body)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	resp, err := http.DefaultClient.Do(proxyReq)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadGateway)
		return
	}
	defer resp.Body.Close()

	sc.metrics.RecordRequest(r.URL.Path, time.Since(start), resp.StatusCode)

	for key, values := range resp.Header {
		for _, value := range values {
			w.Header().Add(key, value)
		}
	}
	w.WriteHeader(resp.StatusCode)
	io.Copy(w, resp.Body)
}

func (sc *Sidecar) healthHandler(w http.ResponseWriter, r *http.Request) {
	w.WriteHeader(http.StatusOK)
	w.Write([]byte(`{"status":"healthy"}`))
}

func (sc *Sidecar) metricsHandler(w http.ResponseWriter, r *http.Request) {
	sc.metrics.WritePrometheus(w)
}

package saga

import (
	"context"
	"fmt"
	"log"
)

type Step struct {
	Name     string
	Execute  func(ctx context.Context, data map[string]interface{}) error
	Compensate func(ctx context.Context, data map[string]interface{}) error
}

type Saga struct {
	name   string
	steps  []Step
	data   map[string]interface{}
	logger *log.Logger
}

func NewSaga(name string) *Saga {
	return &Saga{
		name: name,
		data: make(map[string]interface{}),
		logger: log.New(os.Stdout, "[saga] ", log.LstdFlags),
	}
}

func (s *Saga) AddStep(name string, execute, compensate func(ctx context.Context, data map[string]interface{}) error) *Saga {
	s.steps = append(s.steps, Step{Name: name, Execute: execute, Compensate: compensate})
	return s
}

func (s *Saga) Execute(ctx context.Context) error {
	executedSteps := make([]int, 0)

	for i, step := range s.steps {
		s.logger.Printf("Executing step: %s", step.Name)
		if err := step.Execute(ctx, s.data); err != nil {
			s.logger.Printf("Step %s failed: %v", step.Name, err)
			return s.compensate(ctx, executedSteps)
		}
		executedSteps = append(executedSteps, i)
	}

	s.logger.Printf("Saga %s completed successfully", s.name)
	return nil
}

func (s *Saga) compensate(ctx context.Context, executedSteps []int) error {
	s.logger.Printf("Compensating saga %s", s.name)

	for i := len(executedSteps) - 1; i >= 0; i-- {
		stepIdx := executedSteps[i]
		step := s.steps[stepIdx]
		s.logger.Printf("Compensating step: %s", step.Name)
		if err := step.Compensate(ctx, s.data); err != nil {
			s.logger.Printf("Compensation failed for step %s: %v", step.Name, err)
			return err
		}
	}

	return nil
}

func main() {
	saga := NewSaga("OrderProcessing")
	saga.AddStep("ReserveInventory",
		reserveInventory,
		releaseInventory,
	).AddStep("ProcessPayment",
		processPayment,
		refundPayment,
	).AddStep("CreateShipment",
		createShipment,
		cancelShipment,
	)

	err := saga.Execute(context.Background())
	if err != nil {
		log.Fatalf("Saga failed: %v", err)
	}
}

package gateway

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"
)

type Route struct {
	PathPrefix string
	Target     *url.URL
	Auth       bool
	RateLimit  int
}

type Gateway struct {
	routes   map[string]*Route
	reverseProxies map[string]*httputil.ReverseProxy
	middleware []Middleware
}

func NewGateway() *Gateway {
	return &Gateway{
		routes:         make(map[string]*Route),
		reverseProxies: make(map[string]*httputil.ReverseProxy),
	}
}

func (g *Gateway) AddRoute(pathPrefix string, targetURL string, auth bool) error {
	target, err := url.Parse(targetURL)
	if err != nil {
		return err
	}

	route := &Route{PathPrefix: pathPrefix, Target: target, Auth: auth}
	g.routes[pathPrefix] = route

	proxy := httputil.NewSingleHostReverseProxy(target)
	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		log.Printf("Proxy error for %s: %v", pathPrefix, err)
		http.Error(w, "Service unavailable", http.StatusBadGateway)
	}
	g.reverseProxies[pathPrefix] = proxy

	return nil
}

func (g *Gateway) Handler() http.Handler {
	mux := http.NewServeMux()

	for prefix, proxy := range g.reverseProxies {
		p := prefix
		px := proxy
		mux.Handle(p, http.StripPrefix(p, px))
	}

	return g.applyMiddleware(mux)
}

func (g *Gateway) applyMiddleware(next http.Handler) http.Handler {
	for _, mw := range g.middleware {
		next = mw(next)
	}
	return next
}

func main() {
	gw := NewGateway()
	gw.AddRoute("/api/users", "http://user-service:8080", true)
	gw.AddRoute("/api/orders", "http://order-service:8080", true)
	gw.AddRoute("/api/products", "http://product-service:8080", false)

	server := &http.Server{
		Addr:         ":8080",
		Handler:      gw.Handler(),
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
	}

	log.Println("API Gateway starting on :8080")
	server.ListenAndServe()
}

package events

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"time"

	nats "github.com/nats-io/nats.go"
)

type EventPublisher struct {
	conn *nats.Conn
	logger *log.Logger
}

func NewEventPublisher(url string) (*EventPublisher, error) {
	conn, err := nats.Connect(url,
		nats.Name("OrderService"),
		nats.MaxReconnects(10),
		nats.ReconnectWait(2*time.Second),
		nats.ClosedHandler(func(c *nats.Conn) {
			log.Println("NATS connection closed")
		}),
	)
	if err != nil {
		return nil, err
	}

	return &EventPublisher{conn: conn, logger: log.New(os.Stdout, "[events] ", log.LstdFlags)}, nil
}

func (ep *EventPublisher) PublishOrderCreated(ctx context.Context, orderID string, customerID string) error {
	event := OrderCreatedEvent{
		OrderID:    orderID,
		CustomerID: customerID,
		Timestamp:  time.Now(),
	}

	payload, err := json.Marshal(event)
	if err != nil {
		return err
	}

	subject := fmt.Sprintf("orders.created.%s", customerID)
	err = ep.conn.Publish(subject, payload)
	if err != nil {
		return fmt.Errorf("publish failed: %w", err)
	}

	ep.logger.Printf("Published event: %s -> %s", subject, orderID)
	return nil
}

func (ep *EventPublisher) PublishOrderPaid(ctx context.Context, orderID string, amount float64) error {
	event := OrderPaidEvent{
		OrderID: orderID,
		Amount:  amount,
		Time:    time.Now(),
	}

	payload, _ := json.Marshal(event)
	return ep.conn.Publish("orders.paid", payload)
}

type OrderCreatedEvent struct {
	OrderID    string    `json:"order_id"`
	CustomerID string    `json:"customer_id"`
	Timestamp  time.Time `json:"timestamp"`
}

type OrderPaidEvent struct {
	OrderID string  `json:"order_id"`
	Amount  float64 `json:"amount"`
	Time    time.Time `json:"time"`
}

func (ep *EventPublisher) Close() {
	if ep.conn != nil {
		ep.conn.Drain()
	}
}
